namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string Category { get; set; } = "Breakfast";
}

public static class RecipeStore
{
    public static List<string> Categories { get; } = new()
    {
        "Breakfast", "Lunch", "Dinner", "Desserts", "Snacks", "Beverages"
    };

    public static List<Recipe> Recipes { get; } = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Ingredients = new() { "2 cups flour", "2 eggs", "1.5 cups milk", "2 tbsp sugar", "1 tsp baking powder" },
            Steps = new() { "Mix dry ingredients.", "Whisk eggs and milk together.", "Combine wet and dry ingredients.", "Cook on griddle until golden." },
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Caesar Salad", Category = "Lunch",
            Ingredients = new() { "Romaine lettuce", "Croutons", "Parmesan cheese", "Caesar dressing", "Lemon juice" },
            Steps = new() { "Wash and chop lettuce.", "Toss with dressing.", "Add croutons and parmesan.", "Squeeze lemon on top." },
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
            Ingredients = new() { "400g spaghetti", "500g ground beef", "1 can tomatoes", "1 onion", "3 cloves garlic", "Basil" },
            Steps = new() { "Cook spaghetti al dente.", "Brown the beef with onion and garlic.", "Add tomatoes and simmer 20 min.", "Serve sauce over pasta with fresh basil." },
            AverageRating = 4.8, RatingCount = 20
        },
        new Recipe
        {
            Id = 4, Title = "Chocolate Brownies", Category = "Desserts",
            Ingredients = new() { "200g dark chocolate", "150g butter", "3 eggs", "1 cup sugar", "0.5 cup flour" },
            Steps = new() { "Melt chocolate and butter.", "Beat eggs with sugar.", "Fold in chocolate mixture and flour.", "Bake at 180°C for 25 minutes." },
            AverageRating = 4.9, RatingCount = 15
        },
        new Recipe
        {
            Id = 5, Title = "Guacamole", Category = "Snacks",
            Ingredients = new() { "3 ripe avocados", "1 lime", "1 tsp salt", "0.5 cup cilantro", "1 jalapeño", "1 tomato" },
            Steps = new() { "Mash avocados in a bowl.", "Stir in lime juice and salt.", "Mix in cilantro, jalapeño, and tomato.", "Serve with tortilla chips." },
            AverageRating = 4.6, RatingCount = 10
        },
        new Recipe
        {
            Id = 6, Title = "Iced Latte", Category = "Beverages",
            Ingredients = new() { "2 shots espresso", "1 cup milk", "Ice cubes", "Sugar to taste" },
            Steps = new() { "Brew espresso and let cool slightly.", "Fill a glass with ice.", "Pour milk over ice.", "Add espresso on top and stir." },
            AverageRating = 4.3, RatingCount = 6
        }
    };
}

