﻿@page "/"
@using RecipeHub.Models

<PageTitle>RecipeHub - Recipe Sharing Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 RecipeHub</h1>
    <p class="lead">Discover and share delicious recipes with our community</p>
</div>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeStore.Categories)
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetCategoryEmoji(category) @category</h4>
                    <p class="card-text">@GetRecipeCount(category) recipes</p>
                    <a href="/recipes/@category.ToLower()" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private int GetRecipeCount(string category) =>
        RecipeStore.Recipes.Count(r => r.Category == category);

    private string GetCategoryEmoji(string category) => category switch
    {
        "Breakfast" => "🥞",
        "Lunch" => "🥗",
        "Dinner" => "🍝",
        "Desserts" => "🍫",
        "Snacks" => "🥑",
        "Beverages" => "☕",
        _ => "🍽️"
    };
}

