@rendermode InteractiveServer

<div class="star-rating">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

<style>
    .star-rating .star {
        font-size: 1.5rem;
        cursor: pointer;
        color: #ffc107;
        transition: transform 0.1s;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (isSubmitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@submission.Title</strong>" with the community.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="submission.Title" placeholder="e.g. Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
                @foreach (var cat in RecipeStore.Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="submission.Ingredients"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="submission.Steps"
                           placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
        </div>

        <button type="submit" class="btn btn-success"
                disabled="@(string.IsNullOrWhiteSpace(submission.Title))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool isSubmitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title))
            return;

        isSubmitted = true;
    }

    private void Reset()
    {
        submission = new();
        isSubmitted = false;
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
